import type { CSSProperties } from 'react';
import type { CustomerGroupDto } from '../services/master/models';
import type { SelectOption } from '@linm-soft-org/linm-web-common-components';

/** MM Ant Design Table `indentSize={20}` — tree row padding. */
export const CUSTOMER_GROUP_INDENT_PX = 16;

/** Max tree depth — 4 cấp nhóm đối tượng. */
export const MAX_CUSTOMER_GROUP_LEVEL = 4;

export type CustomerGroupTreeRow = CustomerGroupDto & { parentId?: string | null };

/** BE JSON `parentId` → FE `parentCustomerGroupId`. */
export function normalizeCustomerGroupDto(g: CustomerGroupTreeRow): CustomerGroupDto {
  const parentRaw = g.parentCustomerGroupId ?? g.parentId;
  return {
    ...g,
    customerGroupId: String(g.customerGroupId),
    parentCustomerGroupId: parentRaw ? String(parentRaw) : undefined,
  };
}

/** BE list DTO uses `parentId`; FE form uses `parentCustomerGroupId`. */
export function getCustomerGroupParentId(g: CustomerGroupDto | CustomerGroupTreeRow): string | null {
  const row = g as CustomerGroupTreeRow;
  const id = row.parentCustomerGroupId ?? row.parentId;
  return id ? String(id) : null;
}

/** Tree preload — load full catalog for client flatten (parity material-groups). */
export const CUSTOMER_GROUP_TREE_PRELOAD_SIZE = 2000;

/**
 * Client filter may drop parents — re-attach ancestor chain from full pool before flatten.
 */
export function includeCustomerGroupTreeAncestors(
  selected: CustomerGroupDto[],
  pool: CustomerGroupDto[],
): CustomerGroupDto[] {
  const byId = new Map(
    pool.map(g => [String(g.customerGroupId), normalizeCustomerGroupDto(g)]),
  );
  const out = new Map<string, CustomerGroupDto>();
  for (const row of selected) {
    let current: CustomerGroupDto | undefined = normalizeCustomerGroupDto(row);
    while (current) {
      out.set(current.customerGroupId, current);
      const parentId = getCustomerGroupParentId(current);
      current = parentId ? byId.get(parentId) : undefined;
    }
  }
  return [...out.values()];
}

/** Mã format nhóm cấp 1 — prefix mã đối tượng dạng {formatCode}.{subprefix} (MasterCode). */
export function resolveLevel1CustomerGroup(
  groupId: string | undefined,
  groups: CustomerGroupDto[],
): CustomerGroupDto | undefined {
  if (!groupId) return undefined;
  const byId = new Map(
    groups.map(g => [String(g.customerGroupId), normalizeCustomerGroupDto(g)]),
  );
  let current = byId.get(String(groupId));
  while (current) {
    const parentId = getCustomerGroupParentId(current);
    if (!parentId) break;
    const parent = byId.get(parentId);
    if (!parent) break;
    current = parent;
  }
  return current;
}

export function resolveLevel1FormatCode(
  groupId: string | undefined,
  groups: CustomerGroupDto[],
): string | undefined {
  return resolveLevel1CustomerGroup(groupId, groups)?.formatCode?.trim() || undefined;
}

/** Mã phân tích gốc theo loại nhóm cấp 1 (legacy MM — 4 nhóm). */
export const CUSTOMER_GROUP_TYPE_CODES: Record<string, string> = {
  Customer: '200',
  Supplier: '300',
  Both: '400',
  Employee: '500',
};

export const CUSTOMER_TYPE_LABELS: Record<string, string> = {
  Customer: 'Khách hàng',
  Supplier: 'Nhà cung cấp',
  Both: 'Cả hai',
  Employee: 'Nhân viên',
};

/** SSOT — 4 loại nhóm ↔ mã phân tích (nav + đếm; Both vẫn hiển thị nếu có dữ liệu cũ). */
export const CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER = [
  'Customer',
  'Supplier',
  'Both',
  'Employee',
] as const;

/** Loại nhóm — Select tạo/sửa nhóm (ẩn Both / «Cả hai»). */
export const CUSTOMER_GROUP_TYPE_SELECT_ORDER = [
  'Customer',
  'Supplier',
  'Employee',
] as const;

const HIDDEN_CUSTOMER_GROUP_TYPES = new Set<string>(['Both']);

export type CustomerGroupAnalysisType = (typeof CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER)[number];

export function resolveCustomerGroupAnalysisCode(customerType?: string | null): string {
  const key = customerType?.trim() ?? '';
  return CUSTOMER_GROUP_TYPE_CODES[key] ?? CUSTOMER_GROUP_TYPE_CODES.Employee;
}

/** Fallback Select nhóm đối tượng — không gồm Both. */
export function getCustomerTypeSelectFallback(): SelectOption[] {
  return CUSTOMER_GROUP_TYPE_SELECT_ORDER.map(type => ({
    value: type,
    label: CUSTOMER_TYPE_LABELS[type],
  }));
}

export function filterCustomerTypeSelectOptions(options: SelectOption[]): SelectOption[] {
  return options.filter(o => !HIDDEN_CUSTOMER_GROUP_TYPES.has(String(o.value)));
}

/** Khách hàng — nhập mã tay; NCC vẫn có thể tự sinh theo nhóm. */
export function isManualCustomerCodeType(customerType?: string | null): boolean {
  return String(customerType ?? '').trim() === 'Customer';
}

const TYPE_LABEL_FALLBACK: SelectOption[] = getCustomerTypeSelectFallback();

/** Nhãn VN loại đối tượng — dùng khi init chưa có hoặc grid schema. */
export function resolveCustomerTypeLabel(
  value?: string | null,
  initOptions: SelectOption[] = [],
): string {
  if (!value?.trim()) return '';
  const fromInit = initOptions.find(o => String(o.value) === value)?.label;
  if (fromInit) return fromInit;
  return CUSTOMER_TYPE_LABELS[value] ?? value;
}

/** Distinct Loại options from loaded nhóm đối tượng (catalog), fallback when empty. */
export function buildCustomerTypeOptionsFromGroups(
  groups: CustomerGroupDto[],
  fallback: SelectOption[] = TYPE_LABEL_FALLBACK,
): SelectOption[] {
  const seen = new Set<string>();
  const opts: SelectOption[] = [];
  for (const g of groups) {
    const t = g.customerType?.trim();
    if (!t || seen.has(t) || HIDDEN_CUSTOMER_GROUP_TYPES.has(t)) continue;
    seen.add(t);
    opts.push({ value: t, label: CUSTOMER_TYPE_LABELS[t] ?? t });
  }
  return opts.length > 0 ? opts : fallback;
}

export type CustomerGroupTreeNode = CustomerGroupDto & { children: CustomerGroupTreeNode[] };

/** Loại master (nhóm cấp 1) — SSOT cho nav cascade + đếm ĐT theo nhánh. */
export function resolveMasterLevelCustomerType(
  groupId: string | undefined,
  groups: CustomerGroupDto[],
): CustomerGroupAnalysisType {
  const master = resolveLevel1CustomerGroup(groupId, groups);
  const raw = master?.customerType?.trim() ?? 'Employee';
  return (CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER as readonly string[]).includes(raw)
    ? (raw as CustomerGroupAnalysisType)
    : 'Employee';
}

/** Tổng số ĐT theo nhánh master level 1 (sum customerCount từng nhóm trong nhánh). */
export function countCustomersByMasterType(
  groups: CustomerGroupDto[],
  type: CustomerGroupAnalysisType,
): number {
  const normalized = groups.filter(g => g.isActive).map(g => normalizeCustomerGroupDto(g));
  let total = 0;
  for (const g of normalized) {
    if (resolveMasterLevelCustomerType(g.customerGroupId, normalized) === type) {
      total += g.customerCount ?? 0;
    }
  }
  return total;
}

export type CustomerTypeNavCounts = Partial<Record<CustomerGroupAnalysisType, number>>;

/** Map BE `CustomerTypeCountsDto` → nav section counts (parity list filter customerType). */
export function buildCustomerTypeNavCountMap(
  apiCounts?: {
    customer: number;
    supplier: number;
    both: number;
    employee: number;
  } | null,
): CustomerTypeNavCounts {
  if (!apiCounts) return {};
  return {
    Customer: apiCounts.customer,
    Supplier: apiCounts.supplier,
    Both: apiCounts.both,
    Employee: apiCounts.employee,
  };
}

/**
 * Đếm nav theo loại — ưu tiên aggregate BE (field CustomerType);
 * fallback sum nhóm khi API chưa load.
 */
export function buildCustomerGroupTypeCountMap(
  groups: CustomerGroupDto[],
  typeNavCounts?: CustomerTypeNavCounts | null,
): Partial<Record<CustomerGroupAnalysisType, number>> {
  const counts: Partial<Record<CustomerGroupAnalysisType, number>> = {};
  const hasApi = typeNavCounts && Object.keys(typeNavCounts).length > 0;
  for (const type of CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER) {
    const fromGroups = countCustomersByMasterType(groups, type);
    counts[type] = hasApi
      ? Math.max(fromGroups, typeNavCounts![type] ?? 0)
      : fromGroups;
  }
  return counts;
}

export type CustomerGroupNavSelection =
  | { kind: 'all' }
  | { kind: 'type'; customerType: CustomerGroupAnalysisType }
  | { kind: 'group'; customerGroupId: string };

/** Số ĐT kỳ vọng theo nav — `null` = Tất cả (gọi API). */
export function resolveCustomerGroupNavListCount(
  selection: CustomerGroupNavSelection,
  groups: CustomerGroupDto[],
  typeCounts: Partial<Record<CustomerGroupAnalysisType, number>>,
): number | null {
  if (selection.kind === 'all') return null;
  if (selection.kind === 'type') return typeCounts[selection.customerType] ?? 0;
  const group = groups.find(g => String(g.customerGroupId) === String(selection.customerGroupId));
  return group?.customerCount ?? 0;
}

/** Nav chọn nhánh không có ĐT — grid phải rỗng, không gọi API loại (Both gộp sai). */
export function isCustomerGroupNavEmpty(
  selection: CustomerGroupNavSelection,
  groups: CustomerGroupDto[],
  typeCounts: Partial<Record<CustomerGroupAnalysisType, number>>,
): boolean {
  const count = resolveCustomerGroupNavListCount(selection, groups, typeCounts);
  return count !== null && count === 0;
}

/** Nav từ BE `customers/list-nav` — FE chỉ hiển thị. */
export function isCustomerListNavSelectionEmpty(
  selection: CustomerGroupNavSelection,
  nav: {
    sections: Array<{ sectionId: string; count: number }>;
    nodeCountsByNodeId: Record<string, number>;
  } | null,
): boolean {
  if (!nav) return false;
  if (selection.kind === 'all') return false;
  if (selection.kind === 'type') {
    const section = nav.sections.find(s => s.sectionId === selection.customerType);
    return (section?.count ?? 0) === 0;
  }
  return (nav.nodeCountsByNodeId[selection.customerGroupId] ?? 0) === 0;
}

/** DFS tree nodes — parity `CustomerGroupCascadeNav` / `flattenCustomerGroupTree`. */
export function buildCustomerGroupTreeNodes(groups: CustomerGroupDto[]): CustomerGroupTreeNode[] {
  const normalized = groups
    .filter(g => g.isActive)
    .map(g => normalizeCustomerGroupDto(g));
  const idSet = new Set(normalized.map(g => g.customerGroupId));
  const childrenOf = new Map<string | null, CustomerGroupDto[]>();

  for (const g of normalized) {
    let parentKey = getCustomerGroupParentId(g);
    if (parentKey && !idSet.has(parentKey)) parentKey = null;
    const list = childrenOf.get(parentKey);
    if (list) list.push(g);
    else childrenOf.set(parentKey, [g]);
  }

  for (const list of childrenOf.values()) {
    list.sort(defaultSiblingCompare);
  }

  const toNode = (g: CustomerGroupDto): CustomerGroupTreeNode => ({
    ...g,
    children: (childrenOf.get(g.customerGroupId) ?? []).map(toNode),
  });

  return (childrenOf.get(null) ?? []).map(toNode);
}

/** Cây nhóm cấp 1 theo loại master (customerType của nhóm L1). */
export function customerGroupNavRootsByMasterType(
  groups: CustomerGroupDto[],
): Map<CustomerGroupAnalysisType, CustomerGroupTreeNode[]> {
  const roots = buildCustomerGroupTreeNodes(groups);
  const map = new Map<CustomerGroupAnalysisType, CustomerGroupTreeNode[]>();
  for (const type of CUSTOMER_GROUP_ANALYSIS_TYPE_ORDER) {
    map.set(
      type,
      roots.filter(r => resolveMasterLevelCustomerType(r.customerGroupId, groups) === type),
    );
  }
  return map;
}

/** Chuỗi id nhóm cha (leaf → root) — mở rộng nav khi chọn nhóm con. */
export function collectCustomerGroupAncestorIds(
  groupId: string,
  groups: CustomerGroupDto[],
): string[] {
  const byId = new Map(
    groups.map(g => [String(g.customerGroupId), normalizeCustomerGroupDto(g)]),
  );
  const ancestors: string[] = [];
  let current = byId.get(groupId);
  while (current) {
    const parentId = getCustomerGroupParentId(current);
    if (!parentId) break;
    ancestors.push(parentId);
    current = byId.get(parentId);
  }
  return ancestors;
}

/** Nhóm đối tượng options for Select (value = customerGroupId). */
export function buildCustomerGroupSelectOptions(groups: CustomerGroupDto[]): SelectOption[] {
  return groups
    .filter(g => g.isActive)
    .sort((a, b) => a.code.localeCompare(b.code, 'vi', { numeric: true }))
    .map(g => ({ value: g.customerGroupId, label: `${g.code} — ${g.name}` }));
}

const defaultSiblingCompare = (a: CustomerGroupDto, b: CustomerGroupDto) =>
  a.code.localeCompare(b.code, 'vi', { numeric: true });

/**
 * Flatten depth-first: cha → con (con ngay dưới cha, thụt lề).
 * Siblings sorted by `compareSiblings` (default: mã).
 */
export function flattenCustomerGroupTree(
  items: CustomerGroupDto[],
  compareSiblings?: (a: CustomerGroupDto, b: CustomerGroupDto) => number,
): CustomerGroupDto[] {
  const compare = compareSiblings ?? defaultSiblingCompare;
  const normalized = items.map(g => normalizeCustomerGroupDto(g));
  const idSet = new Set(normalized.map(g => g.customerGroupId));

  const childrenOf = new Map<string | null, CustomerGroupDto[]>();
  for (const g of normalized) {
    let parentKey = getCustomerGroupParentId(g);
    if (parentKey && !idSet.has(parentKey)) {
      parentKey = null;
    }
    const list = childrenOf.get(parentKey);
    if (list) list.push(g);
    else childrenOf.set(parentKey, [g]);
  }

  for (const list of childrenOf.values()) {
    list.sort(compare);
  }

  const out: CustomerGroupDto[] = [];
  const visit = (parentId: string | null) => {
    for (const g of childrenOf.get(parentId) ?? []) {
      out.push(g);
      visit(g.customerGroupId);
    }
  };
  visit(null);
  return out;
}

export function customerGroupRowIndent(level?: number): number {
  return Math.max(0, (level ?? 1) - 1) * CUSTOMER_GROUP_INDENT_PX;
}

/** Tree depth for grid indent — uses BE `level`. */
export function customerGroupRowDepth(row: CustomerGroupDto): number {
  return Math.max(1, row.level ?? 1);
}

/** Grid cell style from BE fontColor / backgroundColor (nhóm cấp 1). */
export function customerGroupRowCellStyle(row: CustomerGroupDto): CSSProperties | undefined {
  if (!row.backgroundColor && !row.fontColor) return undefined;
  return {
    backgroundColor: row.backgroundColor ?? undefined,
    color: row.fontColor ?? undefined,
  };
}

export type CustomerGroupLevelKeys = {
  idKey: `customerGroup${1 | 2 | 3 | 4}Id`;
  codeKey: `customerGroup${1 | 2 | 3 | 4}Code`;
  nameKey: `customerGroup${1 | 2 | 3 | 4}Name`;
};

export function customerGroupLevelKeys(level: number): CustomerGroupLevelKeys {
  const n = Math.min(4, Math.max(1, level));
  return {
    idKey: `customerGroup${n}Id` as CustomerGroupLevelKeys['idKey'],
    codeKey: `customerGroup${n}Code` as CustomerGroupLevelKeys['codeKey'],
    nameKey: `customerGroup${n}Name` as CustomerGroupLevelKeys['nameKey'],
  };
}

/** Chain từ leaf groupId → patch 4 cấp id/code/name. */
export function resolveCustomerGroupChainPatch(
  leafGroupId: string | undefined,
  groups: CustomerGroupDto[],
): Record<string, string> {
  if (!leafGroupId?.trim()) return {};
  const byId = new Map(groups.map(g => [g.customerGroupId, normalizeCustomerGroupDto(g)]));
  const chain: CustomerGroupDto[] = [];
  let current = byId.get(leafGroupId);
  while (current) {
    chain.unshift(current);
    const parentId = getCustomerGroupParentId(current);
    current = parentId ? byId.get(parentId) : undefined;
  }

  const patch: Record<string, string> = {};
  chain.forEach((g, index) => {
    const level = index + 1;
    const keys = customerGroupLevelKeys(level);
    patch[keys.idKey] = g.customerGroupId;
    patch[keys.codeKey] = g.code;
    patch[keys.nameKey] = g.name;
  });
  return patch;
}

/** Số cấp nhóm trong chuỗi leaf → root (1–4). */
export function resolveCustomerGroupChainDepth(
  leafGroupId: string | undefined,
  groups: CustomerGroupDto[],
): number {
  if (!leafGroupId?.trim()) return 0;
  const patch = resolveCustomerGroupChainPatch(leafGroupId, groups);
  let depth = 0;
  for (let level = 1; level <= MAX_CUSTOMER_GROUP_LEVEL; level += 1) {
    const id = patch[customerGroupLevelKeys(level).idKey];
    if (id?.trim()) depth = level;
  }
  return depth;
}

/** Xóa nhóm từ cấp `fromLevel` đến 4. */
export function clearCustomerGroupsFromLevel(fromLevel: number): Record<string, string> {
  if (fromLevel > 4) return {};
  const patch: Record<string, string> = {};
  for (let level = fromLevel; level <= 4; level += 1) {
    const keys = customerGroupLevelKeys(level);
    patch[keys.idKey] = '';
    patch[keys.codeKey] = '';
    patch[keys.nameKey] = '';
  }
  return patch;
}

/** customerGroupId = nhóm sâu nhất đã chọn (ưu tiên cấp 4 → 1). */
export function resolveLeafCustomerGroupId(
  form: Record<string, unknown>,
): string | undefined {
  for (let level = 4; level >= 1; level -= 1) {
    const id = String(form[customerGroupLevelKeys(level).idKey] ?? '').trim();
    if (id) return id;
  }
  return undefined;
}
