import React, { useEffect } from 'react';
import { createPortal } from 'react-dom';
import {
  getErpListToolbarActionIcon,
  getErpListToolbarActionLabel,
} from '@linm-soft-org/linm-web-common-components';
import styles from './CatalogRowActionMenu.module.css';

export type CatalogRowMenuAction = 'edit' | 'view' | 'history' | 'renameCode' | 'delete';

export type CatalogRowActionMenuProps = {
  open: boolean;
  x: number;
  y: number;
  onClose: () => void;
  onSelect: (action: CatalogRowMenuAction) => void;
  testIdPrefix: string;
  /** Hiện «Sửa» — ẩn hẳn khi false (không disable). */
  showEdit?: boolean;
  /** Hiện «Xem» — khi không có quyền write hoặc row readonly shared. */
  showView?: boolean;
  showHistory?: boolean;
  showRename?: boolean;
  showDelete?: boolean;
};

export const CatalogRowActionMenu: React.FC<CatalogRowActionMenuProps> = ({
  open,
  x,
  y,
  onClose,
  onSelect,
  testIdPrefix,
  showEdit = false,
  showView = false,
  showHistory = true,
  showRename = false,
  showDelete = false,
}) => {
  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onClose]);

  if (!open) return null;

  const clampedY = Math.min(y, window.innerHeight - 220);
  const clampedX = Math.min(x, window.innerWidth - 220);

  const pick = (action: CatalogRowMenuAction) => {
    onSelect(action);
    onClose();
  };

  const editLabel = getErpListToolbarActionLabel('edit');
  const viewLabel = getErpListToolbarActionLabel('view');
  const historyLabel = getErpListToolbarActionLabel('history');
  const renameLabel = getErpListToolbarActionLabel('renameCode');
  const deleteLabel = getErpListToolbarActionLabel('delete');

  const hasPrimary = showEdit || showView;
  const hasSecondary = showRename || showDelete;

  return createPortal(
    <>
      <div
        role="presentation"
        style={{ position: 'fixed', inset: 0, zIndex: 1299 }}
        onMouseDown={onClose}
        data-testid={`${testIdPrefix}-row-menu-backdrop`}
      />
      <div
        className={styles.menu}
        style={{ left: clampedX, top: clampedY }}
        role="menu"
        data-testid={`${testIdPrefix}-row-menu`}
      >
        {showEdit ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            onClick={() => pick('edit')}
            data-testid={`${testIdPrefix}-row-menu-edit`}
          >
            <i className={getErpListToolbarActionIcon('edit')} aria-hidden />
            {editLabel}
          </button>
        ) : null}
        {showView ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            onClick={() => pick('view')}
            data-testid={`${testIdPrefix}-row-menu-view`}
          >
            <i className={getErpListToolbarActionIcon('view')} aria-hidden />
            {viewLabel}
          </button>
        ) : null}
        {showHistory ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            onClick={() => pick('history')}
            data-testid={`${testIdPrefix}-row-menu-history`}
          >
            <i className={getErpListToolbarActionIcon('history')} aria-hidden />
            {historyLabel}
          </button>
        ) : null}
        {hasPrimary && hasSecondary ? <div className={styles.separator} /> : null}
        {showRename ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            onClick={() => pick('renameCode')}
            data-testid={`${testIdPrefix}-row-menu-rename`}
          >
            <i className={getErpListToolbarActionIcon('renameCode')} aria-hidden />
            {renameLabel}
          </button>
        ) : null}
        {showDelete ? (
          <button
            type="button"
            className={`${styles.item} ${styles.itemDanger}`}
            role="menuitem"
            onClick={() => pick('delete')}
            data-testid={`${testIdPrefix}-row-menu-delete`}
          >
            <i className={getErpListToolbarActionIcon('delete')} aria-hidden />
            {deleteLabel}
          </button>
        ) : null}
      </div>
    </>,
    document.body,
  );
};
