import React, { useMemo } from 'react';
import { Button, Checkbox, Input, SearchInput, Select, type SelectOption } from '@linm-soft-org/linm-web-common-components';
import { resolveInitOptionLabel } from '../../../utils/initOptionLabel';
import { createSupplierContractSearchConfig } from '../../search/supplierContractSearchConfig';
import type { SupplierContractDto } from '../../../services/master/models';
import type {
  CustomerBankAccountLine,
  CustomerDiscountTermLine,
} from '../../../services/master/customerDetailModels';
import { emptyBankAccountLine, emptyDiscountTermLine } from '../../../services/master/customerDetailModels';
import { detailGridSelectLock, detailGridTextLock } from '../../../utils/formViewLock';
import df from '../../../styles/documentForm.module.css';
import styles from './CustomerDetailGrids.module.css';

function gridWrapClass(viewOnly: boolean): string {
  return [styles.gridWrap, viewOnly ? df.viewReadOnlySection : ''].filter(Boolean).join(' ');
}

function EmptyGridRow({ colSpan }: { colSpan: number }): React.ReactElement {
  return (
    <tr>
      <td colSpan={colSpan} className={styles.emptyRow}>
        Chưa có dữ liệu
      </td>
    </tr>
  );
}

function formatPercent(value?: number): string {
  if (value == null || Number.isNaN(value)) return '';
  return `${value}%`;
}

function formatDate(value?: string): string {
  if (!value?.trim()) return '';
  const d = value.slice(0, 10);
  const [y, m, day] = d.split('-');
  if (!y || !m || !day) return value;
  return `${day}/${m}/${y}`;
}

function toDateInputValue(value?: string): string {
  if (!value?.trim()) return '';
  return value.slice(0, 10);
}

function parsePercentInput(raw: string): number | undefined {
  const v = raw.trim().replace('%', '');
  if (!v) return undefined;
  const n = Number(v);
  return Number.isNaN(n) ? undefined : n;
}

type GridProps<T> = {
  rows: T[];
  viewOnly: boolean;
  onChange?: (rows: T[]) => void;
  testIdPrefix: string;
};

type BankGridProps = GridProps<CustomerBankAccountLine> & {
  bankKindOptions?: SelectOption[];
};

export const CustomerBankAccountGrid: React.FC<BankGridProps> = ({
  rows,
  viewOnly,
  onChange,
  testIdPrefix,
  bankKindOptions = [],
}) => {
  const textLock = detailGridTextLock(viewOnly);
  const selectLock = detailGridSelectLock(viewOnly);

  const update = (idx: number, patch: Partial<CustomerBankAccountLine>) => {
    onChange?.(rows.map((r, i) => (i === idx ? { ...r, ...patch } : r)));
  };

  const colSpan = viewOnly ? 6 : 7;

  return (
    <div className={gridWrapClass(viewOnly)} data-testid={`${testIdPrefix}-bank-grid`}>
      <div className={styles.tableScroll}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th>Loại TK</th>
              <th>Ngân hàng</th>
              <th>Số tài khoản</th>
              <th>Chi nhánh</th>
              <th>Chủ tài khoản</th>
              <th>Chính</th>
              {!viewOnly ? <th /> : null}
            </tr>
          </thead>
          <tbody>
            {rows.length === 0 ? (
              <EmptyGridRow colSpan={colSpan} />
            ) : (
              rows.map((row, idx) => (
                <tr key={row.id ?? `bank-${idx}`}>
                  <td>
                    {viewOnly ? (
                      <Input
                        value={resolveInitOptionLabel(bankKindOptions, row.accountKind)}
                        {...textLock}
                        readOnly
                      />
                    ) : (
                      <Select
                        value={row.accountKind || 'Company'}
                        options={bankKindOptions}
                        {...selectLock}
                        onChange={e => update(idx, { accountKind: e.target.value })}
                      />
                    )}
                  </td>
                  <td>
                    <Input
                      value={row.bankName}
                      {...textLock}
                      readOnly={viewOnly}
                      onChange={e => update(idx, { bankName: e.target.value })}
                    />
                  </td>
                  <td>
                    <Input
                      value={row.accountNumber}
                      {...textLock}
                      readOnly={viewOnly}
                      onChange={e => update(idx, { accountNumber: e.target.value })}
                    />
                  </td>
                  <td>
                    <Input
                      value={row.branchName ?? ''}
                      {...textLock}
                      readOnly={viewOnly}
                      onChange={e => update(idx, { branchName: e.target.value })}
                    />
                  </td>
                  <td>
                    <Input
                      value={row.accountHolder ?? ''}
                      {...textLock}
                      readOnly={viewOnly}
                      onChange={e => update(idx, { accountHolder: e.target.value })}
                    />
                  </td>
                  <td>
                    {viewOnly ? (
                      <Input value={row.isPrimary ? 'Có' : ''} {...textLock} readOnly />
                    ) : (
                      <Checkbox
                        id={`${testIdPrefix}-bank-primary-${idx}`}
                        checked={row.isPrimary}
                        {...selectLock}
                        onChange={e => update(idx, { isPrimary: e.target.checked })}
                      />
                    )}
                  </td>
                  {!viewOnly ? (
                    <td>
                      <Button
                        variant="secondary"
                        onClick={() => onChange?.(rows.filter((_, i) => i !== idx))}
                      >
                        Xóa
                      </Button>
                    </td>
                  ) : null}
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
      {!viewOnly ? (
        <Button
          variant="secondary"
          data-testid={`${testIdPrefix}-bank-add-row`}
          onClick={() => onChange?.([...rows, emptyBankAccountLine(rows.length)])}
        >
          Thêm dòng
        </Button>
      ) : null}
    </div>
  );
};

type DiscountGridProps = GridProps<CustomerDiscountTermLine> & {
  /** Có giá trị — cột Số HĐ dùng lookup danh mục HĐ NCC. */
  supplierCustomerId?: string;
};

export const CustomerDiscountTermGrid: React.FC<DiscountGridProps> = ({
  rows,
  viewOnly,
  onChange,
  testIdPrefix,
  supplierCustomerId,
}) => {
  const textLock = detailGridTextLock(viewOnly);
  const colSpan = viewOnly ? 13 : 14;
  const contractSearchConfig = useMemo(
    () => (supplierCustomerId ? createSupplierContractSearchConfig(supplierCustomerId) : null),
    [supplierCustomerId],
  );

  const update = (idx: number, patch: Partial<CustomerDiscountTermLine>) => {
    onChange?.(rows.map((r, i) => (i === idx ? { ...r, ...patch } : r)));
  };

  const percentCell = (
    row: CustomerDiscountTermLine,
    idx: number,
    key: keyof CustomerDiscountTermLine,
  ) => {
    const val = row[key] as number | undefined;
    if (viewOnly) {
      return <Input value={formatPercent(val)} {...textLock} readOnly />;
    }
    return (
      <Input
        type="number"
        min={0}
        max={100}
        step={0.01}
        value={val != null ? String(val) : ''}
        onChange={e => update(idx, { [key]: parsePercentInput(e.target.value) } as Partial<CustomerDiscountTermLine>)}
      />
    );
  };

  const dateCell = (
    row: CustomerDiscountTermLine,
    idx: number,
    key: 'contractDate' | 'effectiveFrom' | 'effectiveTo',
  ) => {
    if (viewOnly) {
      return <Input value={formatDate(row[key])} {...textLock} readOnly />;
    }
    return (
      <Input
        type="date"
        value={toDateInputValue(row[key])}
        onChange={e => update(idx, { [key]: e.target.value } as Partial<CustomerDiscountTermLine>)}
      />
    );
  };

  return (
    <div className={gridWrapClass(viewOnly)} data-testid={`${testIdPrefix}-discount-grid`}>
      <div className={styles.tableScroll}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th>Hợp đồng NCC</th>
              <th>Ngày ký</th>
              <th>Từ ngày</th>
              <th>Đến ngày</th>
              <th>Chiết khấu</th>
              <th>HT khai trương</th>
              <th>HT SP mới</th>
              <th>HT sinh nhật</th>
              <th>HT vận chuyển</th>
              <th>HT trưng bày</th>
              <th>TT đúng hạn</th>
              <th>Thưởng DS</th>
              <th>Ghi chú</th>
              {!viewOnly ? <th /> : null}
            </tr>
          </thead>
          <tbody>
            {rows.length === 0 ? (
              <EmptyGridRow colSpan={colSpan} />
            ) : (
              rows.map((row, idx) => (
                <tr key={row.id ?? `disc-${idx}`}>
                  <td>
                    {viewOnly ? (
                      <Input value={row.contractNumber ?? ''} {...textLock} readOnly />
                    ) : contractSearchConfig ? (
                      <SearchInput
                        config={contractSearchConfig}
                        value={row.contractNumber ?? ''}
                        primaryDisplay={row.contractNumber ?? ''}
                        onChange={(c: SupplierContractDto) => update(idx, {
                          supplierContractId: c.id,
                          contractNumber: c.contractNumber,
                          contractDate: c.contractDate?.slice(0, 10) ?? row.contractDate,
                        })}
                        onClear={() => update(idx, {
                          supplierContractId: undefined,
                          contractNumber: '',
                        })}
                        showLabel={false}
                        showSecondaryInput={false}
                        placeholder="Số HĐ..."
                      />
                    ) : (
                      <Input
                        value={row.contractNumber ?? ''}
                        placeholder="Số HĐ (Lưu lần đầu để tạo danh mục)"
                        onChange={e => update(idx, {
                          contractNumber: e.target.value,
                          supplierContractId: undefined,
                        })}
                      />
                    )}
                  </td>
                  <td>{dateCell(row, idx, 'contractDate')}</td>
                  <td>{dateCell(row, idx, 'effectiveFrom')}</td>
                  <td>{dateCell(row, idx, 'effectiveTo')}</td>
                  <td>{percentCell(row, idx, 'discountPercent')}</td>
                  <td>{percentCell(row, idx, 'openingSupportPercent')}</td>
                  <td>{percentCell(row, idx, 'newProductSupportPercent')}</td>
                  <td>{percentCell(row, idx, 'birthdaySupportPercent')}</td>
                  <td>{percentCell(row, idx, 'shippingSupportPercent')}</td>
                  <td>{percentCell(row, idx, 'displaySupportPercent')}</td>
                  <td>{percentCell(row, idx, 'onTimePaymentBonusPercent')}</td>
                  <td>{percentCell(row, idx, 'salesBonusPercent')}</td>
                  <td>
                    <Input
                      value={row.note ?? ''}
                      {...textLock}
                      readOnly={viewOnly}
                      onChange={e => update(idx, { note: e.target.value })}
                    />
                  </td>
                  {!viewOnly ? (
                    <td>
                      <Button
                        variant="secondary"
                        onClick={() => onChange?.(rows.filter((_, i) => i !== idx))}
                      >
                        Xóa
                      </Button>
                    </td>
                  ) : null}
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
      {!viewOnly ? (
        <Button
          variant="secondary"
          data-testid={`${testIdPrefix}-discount-add-row`}
          onClick={() => onChange?.([...rows, emptyDiscountTermLine(rows.length)])}
        >
          Thêm dòng
        </Button>
      ) : null}
    </div>
  );
};
