import React from 'react';
import { Button } from '@linm-soft-org/linm-web-common-components';
import { isSharedCatalogReadOnly } from '../../hooks/useSharedCatalog';
import { SharedCatalogProposalTrigger } from './SharedCatalogProposalTrigger';
import type { SharedCatalogListMeta } from './SharedCatalogListFooter';
import type { SharedCatalogProposalRow } from './sharedCatalogProposalTypes';
import { proposalValuesFromRow } from './sharedCatalogProposalTypes';
import type { SharedCatalogProposalFieldDef } from './sharedCatalogProposalFieldRegistry';
import styles from '../../styles/erpPage.module.css';

export interface SharedCatalogToolbarActionsProps {
  testIdPrefix: string;
  catalogKind: string;
  meta: SharedCatalogListMeta | null;
  /** Đúng 1 dòng chọn — bắt buộc để mở «Đề xuất». */
  selectedRow?: SharedCatalogProposalRow | null;
  usageActive?: boolean;
  canRequest?: boolean;
  onRequestUsage?: (note?: string) => Promise<void>;
  onSubmitChange?: (
    entityKey: string,
    payload: import('./SharedCatalogProposalModal').SharedCatalogProposalSubmitChange,
  ) => Promise<void>;
  onOpenApprovalQueue?: () => void;
  requesting?: boolean;
  proposalFieldDefs?: SharedCatalogProposalFieldDef[];
}

/** «Đề xuất» + «Chờ duyệt» — catalog list toolbar (trái, sau Làm mới · Lịch sử). */
export const SharedCatalogToolbarActions: React.FC<SharedCatalogToolbarActionsProps> = ({
  testIdPrefix,
  catalogKind,
  meta,
  selectedRow,
  usageActive = false,
  canRequest = false,
  onRequestUsage,
  onSubmitChange,
  onOpenApprovalQueue,
  requesting = false,
  proposalFieldDefs,
}) => {
  const showPropose = canRequest && (meta?.canRequest ?? true);
  const showPending = meta?.usageStatus === 'Pending';
  const showApprovalQueue = meta?.canApprove && onOpenApprovalQueue;

  const row = selectedRow ?? null;
  const isShared = row ? isSharedCatalogReadOnly(row) : false;
  const proposeModes = row
    ? (isShared
      ? (['change'] as const)
      : (usageActive ? (['change', 'usage'] as const) : (['change'] as const)))
    : (['change'] as const);
  const defaultChangeAction = isShared ? 'Update' : 'Create';

  if (!showPropose && !showPending && !showApprovalQueue) return null;

  return (
    <div
      className={styles.catalogToolbarShared}
      data-testid={`${testIdPrefix}-shared-toolbar`}
    >
      {showPropose && (
        <SharedCatalogProposalTrigger
          testIdPrefix={testIdPrefix}
          catalogKind={catalogKind}
          label="Đề xuất"
          iconClass="fas fa-share-alt"
          modes={[...proposeModes]}
          context="item"
          entityKey={row?.code}
          entityLabel={row?.name ?? row?.code}
          defaultChangeAction={defaultChangeAction}
          currentValues={row ? proposalValuesFromRow(row) : undefined}
          disabled={!row || requesting}
          onSubmitUsage={onRequestUsage ?? (async () => {})}
          onSubmitChange={async () => {}}
          onSubmitChangeForEntity={onSubmitChange}
          proposalFieldDefs={proposalFieldDefs}
        />
      )}
      {showPending && (
        <span className={styles.sharedCatalogHint} data-testid={`${testIdPrefix}-usage-pending`}>
          <i className="fas fa-clock" /> Chờ duyệt sử dụng chung
        </span>
      )}
      {showApprovalQueue && (
        <Button
          variant="secondary"
          size="sm"
          data-testid={`${testIdPrefix}-approval-queue-btn`}
          onClick={onOpenApprovalQueue}
        >
          <i className="fas fa-inbox" /> Chờ duyệt
        </Button>
      )}
    </div>
  );
};
