import React from 'react';
import { Outlet, useLocation } from 'react-router-dom';
import { ErpAppLayout, useResponsive } from '@linm-soft-org/linm-web-common-components';
import { ReduxToastContainer } from '@linm-soft-org/linm-web-common-components';
import { isStandalone, showDevNav } from '../../../dev/isStandalone';
import { isCatalogListPath } from '../../../utils/isCatalogListPath';
import styles from './AppLayout.module.css';

const getPageTitle = (pathname: string): string => {
  if (pathname.startsWith('/dev')) return 'Dev Navigation';
  if (pathname.startsWith('/dm')) return 'Danh Mục';
  if (pathname.startsWith('/system')) return 'Hệ Thống';
  return 'ERP Danh Mục';
};

export const AppLayout: React.FC = () => {
  const location = useLocation();
  const { isMobile } = useResponsive();
  const title = getPageTitle(location.pathname);
  const isDevPath = location.pathname.startsWith('/dev');
  const catalogListShell = isCatalogListPath(location.pathname);

  return (
    <ErpAppLayout
      variant="embedded"
      standalone={isStandalone}
      title={title}
      showDevLink={showDevNav && !isDevPath}
      mainClassName={catalogListShell ? styles.mainCatalogListShell : ''}
      contentClassName={catalogListShell ? styles.contentCatalogListShell : ''}
      onMobileMenuToggle={isMobile ? () => window.dispatchEvent(new CustomEvent('linm:nav:toggle-mobile')) : undefined}
    >
      <>
        <Outlet />
        {isStandalone && <ReduxToastContainer />}
      </>
    </ErpAppLayout>
  );
};

export default AppLayout;
