import { useMemo } from 'react';
import {
  useCatalogPermissions,
  type MasterCatalogPermissions,
  type MasterCatalogSharedMeta,
} from '@linm-soft-org/linm-web-common-components';
import { isPermissionsLocalModeActive } from '../dev/isPermissionsLocalMode';

export type { MasterCatalogPermissions, MasterCatalogSharedMeta };

const LOCAL_CATALOG_PERMS: MasterCatalogPermissions = {
  permissionsReady: true,
  canWrite: true,
  canApproveShared: true,
  canRequestShared: true,
  canEditShared: true,
  canEditSharedDirect: true,
  usageStatus: undefined,
  permissionCodes: {
    write: '',
    approve: '',
    request: '',
  },
  hasPermission: () => true,
};

/**
 * Danh mục list/form — quyền write + shared.
 * Local: `VITE_PERMISSIONS_LOCAL_MODE=true` hoặc dev server (`permissions-local-dev-mode.md`).
 */
export function useCatalogListPermissions(
  catalogKind: string,
  sharedMeta?: MasterCatalogSharedMeta | null,
): MasterCatalogPermissions {
  const perms = useCatalogPermissions(catalogKind, sharedMeta);

  return useMemo(() => {
    if (!isPermissionsLocalModeActive()) return perms;
    return {
      ...LOCAL_CATALOG_PERMS,
      permissionCodes: perms.permissionCodes,
      usageStatus: perms.usageStatus ?? sharedMeta?.usageStatus,
    };
  }, [perms, sharedMeta?.usageStatus]);
}
