import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import type { MaterialGroupDto } from '../../services/master/models';
import { createStaticLookupSearchConfig } from './createStaticLookupSearchConfig';

export function createMaterialGroupSearchConfig(
  groups: MaterialGroupDto[],
): SearchInputConfig<MaterialGroupDto> {
  return createStaticLookupSearchConfig({
    loadItems: () => groups,
    getKey: g => g.id,
    getCode: g => g.code,
    getName: g => g.name,
  });
}
